 1	import type { FC } from 'react';
 2	import { AlertMessageForModals } from 'src/modules/Providers/modals/components/AlertMessageForModals';
 3	
 4	import { Stack, StackItem } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	type EditLUKSModalAlertProps = {
 8	  shouldRender: boolean;
 9	};
10	
11	const EditLUKSModalAlert: FC<EditLUKSModalAlertProps> = ({ shouldRender }) => {
12	  const { t } = useForkliftTranslation();
13	
14	  if (!shouldRender) return null;
15	  return (
16	    <AlertMessageForModals
17	      variant="warning"
18	      title={t('The plan LUKS decryption keys were manually configured')}
19	      message={
20	        <Stack hasGutter>
21	          <StackItem>
22	            {t('Warning: not all virtual machines are configures using the same LUKS secret')},
23	          </StackItem>
24	          <StackItem>
25	            {t('updating the LUKS decryption keys will override the current configuration.')}
26	          </StackItem>
27	        </Stack>
28	      }
29	    />
30	  );
31	};
32	
33	export default EditLUKSModalAlert;

